// Method that calculates rectangle area
// It takes width and height as parameters
// It returns the calculated area as a double
public static double calculateArea(double width, double height) {
    // Multiply width by height to get area
    double area = width * height;
    // Send the result back to whoever called this
    return area;
}

public static void main(String[] args) {
    // Call the method and store its return value
    double roomArea = calculateArea(5.0, 8.0);
    System.out.println("Room area: " + roomArea);
}
// Expected output:
// Room area: 40.0
